:root, [data-theme="light"] {
  --bg: #f3e6d8;
  --bg-2: #efd6b8;
  --paper: rgba(255,250,247,.86);
  --paper-2: rgba(244,225,219,.76);
  --paper-3: #eed3cd;
  --text: #14100f;
  --muted: #5f4b47;
  --line: rgba(20,16,15,.12);
  --line-strong: rgba(20,16,15,.2);
  --primary: #d85b50;
  --primary-2: #bb4a4f;
  --primary-soft: #efb0aa;
  --accent: rgba(216,91,80,.12);
  --glow: rgba(216,91,80,.18);
  --image-bg-a: #c05a00;
  --image-bg-mid: #e69323;
  --image-bg-b: #d2c185;
  --shadow: 0 24px 60px rgba(112,58,52,.12);
  --shadow-lg: 0 42px 90px rgba(112,58,52,.18);
