/**
 * useTimelineLayout
 *
 * Observes the timeline section container via ResizeObserver.
 * On each resize:
 *   - Computes ratio = clientHeight / clientWidth
 *   - Sets data-tl-mode="horizontal" (ratio ≤ 1) or "vertical" (ratio > 1)
 *   - Computes --tl-secondary via piecewise linear interpolation:
 *       ratio 0.5  → 0.85   (1:2, wide/short)
 *       ratio 1.0  → 0.45   (1:1, square)
 *       ratio 2.0  → 0.25   (2:1, tall/narrow)
 *     Values outside [0.5, 2.0] are clamped.
 *
 * Writes directly to the DOM element (no React re-render).
 * Returns the ref to attach to .timeline-section.
 */

const KEYFRAMES = [
  { ratio: 0.5, secondary: 0.85 },
  { ratio: 1.0, secondary: 0.45 },
  { ratio: 2.0, secondary: 0.25 },
]

function interpolateSecondary(ratio) {
  // Clamp to keyframe range
  if (ratio <= KEYFRAMES[0].ratio) return KEYFRAMES[0].secondary
  if (ratio >= KEYFRAMES[KEYFRAMES.length - 1].ratio) return KEYFRAMES[KEYFRAMES.length - 1].secondary

  // Find surrounding keyframe pair
  for (let i = 0; i < KEYFRAMES.length - 1; i++) {
    const lo = KEYFRAMES[i]
    const hi = KEYFRAMES[i + 1]
    if (ratio >= lo.ratio && ratio <= hi.ratio) {
      const t = (ratio - lo.ratio) / (hi.ratio - lo.ratio)
      return lo.secondary + t * (hi.secondary - lo.secondary)
    }
  }
  return 0.45 // fallback (square)
}

export function useTimelineLayout() {
  const ref = useRef(null)

  useEffect(() => {
    const el = ref.current
    if (!el) return

    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        const { clientHeight, clientWidth } = entry.target
        if (!clientWidth) return

        const ratio = clientHeight / clientWidth
        const mode = ratio <= 1.0 ? 'horizontal' : 'vertical'
        const secondary = interpolateSecondary(ratio)

        el.dataset.tlMode = mode
        el.style.setProperty('--tl-secondary', secondary.toFixed(4))

        // Temporary: remove before production (Step 10)
        console.log('[timeline]', mode, 'ratio:', ratio.toFixed(3), '--tl-secondary:', secondary.toFixed(3))
      }
    })

    observer.observe(el)
    return () => observer.disconnect()
  }, [])

  return ref
}
"}

